// Establish array view lengths from `wf()` so Seq indexing is well-formed.
assert(pre_self_.page_array@.len() == NUM_PAGES);
assert(post1_self_.page_array@.len() == NUM_PAGES);
assert(post2_self_.page_array@.len() == NUM_PAGES);

// Pointwise equality of the two posts' page_array entries, by case on i==index.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] == post2_self_.page_array@[i] by {
    if i == index as int {
        // At the updated index, every Page field is pinned by an ensures conjunct.
        // Re-assert each one in `=~=` form (matching the ensures syntax) so that
        // Verus instantiates the corresponding conjunct for both runs.
        assert(post1_self_.page_array@[index as int].addr
            =~= pre_self_.page_array@[index as int].addr);
        assert(post2_self_.page_array@[index as int].addr
            =~= pre_self_.page_array@[index as int].addr);
        assert(post1_self_.page_array@[index as int].is_io_page
            =~= pre_self_.page_array@[index as int].is_io_page);
        assert(post2_self_.page_array@[index as int].is_io_page
            =~= pre_self_.page_array@[index as int].is_io_page);
        assert(post1_self_.page_array@[index as int].rev_pointer
            =~= pre_self_.page_array@[index as int].rev_pointer);
        assert(post2_self_.page_array@[index as int].rev_pointer
            =~= pre_self_.page_array@[index as int].rev_pointer);
        assert(post1_self_.page_array@[index as int].ref_count
            =~= pre_self_.page_array@[index as int].ref_count);
        assert(post2_self_.page_array@[index as int].ref_count
            =~= pre_self_.page_array@[index as int].ref_count);
        assert(post1_self_.page_array@[index as int].owning_container
            =~= pre_self_.page_array@[index as int].owning_container);
        assert(post2_self_.page_array@[index as int].owning_container
            =~= pre_self_.page_array@[index as int].owning_container);
        assert(post1_self_.page_array@[index as int].mappings
            =~= pre_self_.page_array@[index as int].mappings);
        assert(post2_self_.page_array@[index as int].mappings
            =~= pre_self_.page_array@[index as int].mappings);
        assert(post1_self_.page_array@[index as int].io_mappings
            =~= pre_self_.page_array@[index as int].io_mappings);
        assert(post2_self_.page_array@[index as int].io_mappings
            =~= pre_self_.page_array@[index as int].io_mappings);
        assert(post1_self_.page_array@[index as int].state =~= state);
        assert(post2_self_.page_array@[index as int].state =~= state);
        // Field-wise `=~=` plus i == index lifts to Page structural equality.
        assert(post1_self_.page_array@[i] =~= post2_self_.page_array@[i]);
    } else {
        // i != index: the per-index forall ensures pins the entry to pre on both
        // runs.  Mention the trigger `post*.page_array@[i]` so the ensures fires.
        assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        assert(post1_self_.page_array@[i] =~= post2_self_.page_array@[i]);
    }
}

// Seq extensionality lifts the pointwise Page equality to view ==.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
